const input = $input.first().json;
const body = input.body ?? input;
const job = body.job ?? {};
const eventId = body.event?.id ?? body.eventId;
const jobId = job.id ?? body.jobId;
const callbackUrl = body.callbackUrl;
const callbackSecret = body.callbackSecret;
const selectedIdea = (job.ideas ?? []).find((idea) => idea.id === (job.selectedIdeaId ?? body.selectedIdeaId)) ?? (job.ideas ?? [])[0] ?? null;
if (!jobId || !eventId || !callbackUrl) {
  return [];
}
const seedKeyword = job.seedKeyword ?? body.seedKeyword ?? 'Untitled topic';
const title = selectedIdea?.title ?? seedKeyword;
const angle = selectedIdea?.angle ?? 'Build a practical SEO brief';
const research = job.research ?? { objective: '', audience: '', gaps: [], sources: [] };
return [{ json: {
  eventId,
  jobId,
  callbackUrl,
  callbackSecret,
  brief: {
    title: `${title} | Practical SEO brief`,
    slug: String(title).toLowerCase().replace(/[^a-z0-9\s-]/g, '').trim().replace(/\s+/g, '-'),
    metaTitle: `${title} | Complete guide`,
    metaDescription: `Structured SEO brief for ${title} with Thai and global context.`,
    audience: research.audience || `Readers searching for ${seedKeyword}`,
    angle,
    outline: [
      `${title}: direct answer and context`,
      'What the reader needs to understand first',
      'Thai-market signals and examples',
      'Global references that strengthen trust',
      'Practical recommendations and cautions',
      'FAQs'
    ],
    faqs: [
      `${seedKeyword} should beginners know what first?`,
      `What mistakes should readers avoid about ${seedKeyword}?`,
      `When should the reader take action immediately?`
    ],
    internalLinks: [
      `${seedKeyword} basics`,
      `${seedKeyword} problems and fixes`,
      `${seedKeyword} buying guide`
    ]
  }
}}];
